int index = i_arg1.RowIndex;
MacRange macRange = (MacRange)m_object.macRangeList.Get(index);
macRange.name += macRange._ObjectId.ToString();

int index = i_arg1.RowIndex;
VlanIdRange vlanRange = (VlanIdRange)m_object.vlanRangeList.Get(index);
vlanRange.name += vlanRange._ObjectId.ToString();

if( m_form.cbAutoNeg.Checked)
{
     if( !m_form.cb10Half.Checked  && 
        !m_form.cb10Full.Checked && 
        !m_form.cb100Half.Checked &&
        !m_form.cbGigaFull.Checked )
	m_form.cb100Full.Checked = true;

}
else
{
      if(m_form.cb100Full.Checked )
     {
	m_form.cb100Half.Checked = false;
                m_form.cb10Full.Checked = false;
                m_form.cb10Half.Checked = false;
     }
     else if( !m_form.cb10Full.Checked  && 
                !m_form.cb100Half.Checked &&
               !m_form.cb10Half.Checked )
	m_form.cb100Full.Checked = true;

}

if( m_form.cbAutoNeg.Checked)
{
     if( !m_form.cb10Full.Checked  && 
        !m_form.cb100Half.Checked &&
        !m_form.cb100Full.Checked &&
        !m_form.cbGigaFull.Checked )
	m_form.cb10Half.Checked = true;

}
else
{
      if(m_form.cb10Half.Checked )
     {
	m_form.cb100Half.Checked = false;
                m_form.cb10Full.Checked = false;
                m_form.cb100Full.Checked = false;
     }
     else if( !m_form.cb10Full.Checked  && 
                !m_form.cb100Half.Checked &&
               !m_form.cb100Full.Checked )
	m_form.cb10Half.Checked = true;

}

if( m_form.cbAutoNeg.Checked)
{
     if( !m_form.cb10Half.Checked  && 
        !m_form.cb100Half.Checked &&
        !m_form.cb100Full.Checked &&
        !m_form.cbGigaFull.Checked )
	m_form.cb10Full.Checked = true;

}
else
{
      if(m_form.cb10Full.Checked )
     {
	m_form.cb100Half.Checked = false;
                m_form.cb10Half.Checked = false;
                m_form.cb100Full.Checked = false;
     }
     else if( !m_form.cb10Half.Checked  && 
                !m_form.cb100Half.Checked &&
               !m_form.cb100Full.Checked )
	m_form.cb10Full.Checked = true;

}

if( m_form.cbAutoNeg.Checked)
{
     if( !m_form.cb10Half.Checked  && 
        !m_form.cb10Full.Checked && 
        !m_form.cb100Full.Checked &&
        !m_form.cbGigaFull.Checked )
	m_form.cb100Half.Checked = true;

}
else
{
      if(m_form.cb100Half.Checked )
     {
	m_form.cb10Half.Checked = false;
                m_form.cb10Full.Checked = false;
                m_form.cb100Full.Checked = false;
     }
     else if( !m_form.cb10Full.Checked  && 
                !m_form.cb10Half.Checked &&
               !m_form.cb100Full.Checked )
	m_form.cb100Half.Checked = true;
}

if( m_form.cbAutoNeg.Checked   &&  m_form.cbGigaFull.Enabled )
{
     if( !m_form.cb10Half.Checked  && 
        !m_form.cb100Half.Checked &&
        !m_form.cb100Full.Checked &&
        !m_form.cb10Full.Checked ) 
	m_form.cbGigaFull.Checked = true;

}

if(   m_form.cbAutoNeg.Checked )
{
                advertise10Half= false;
	advertise10Full = false;
	advertise100Half = false;
	advertise100Full = true;
                m_form.cb10Half.Checked = false;
                m_form.cb10Full.Checked  = false;

}

aptixia.sm.DynamicGridControlEvent ev = i_arg1;
VlanIdRange vlanRange = null;

try
{
    vlanRange = (VlanIdRange) ev.DataList[ev.RowIndex];
}
catch
{
}

if (vlanRange != null &&
    ev.FieldName == "innerEnable" &&
    vlanRange.innerEnable == true)
{
    vlanRange.enable = true;
}

if (vlanRange != null &&
    ev.FieldName == "enable" &&
    vlanRange.enable == false)
{
    vlanRange.innerEnable = false;
}

aptixia.sm.DynamicGridControlEvent ev = i_arg1;
MacRange macRange = null;
string error = "";

try
{
    macRange = (MacRange) ev.DataList[ev.RowIndex];
}
catch
{
}

if (macRange != null)
{
    if (ev.FieldName == "mac")
    {
        error += Verifier.VerifyMacAddress(ev.Data.ToString());
    }
    if (ev.FieldName == "incrementBy")
    {
        error += Verifier.VerifyMacAddress(ev.Data.ToString());
    }
}

ev.Error = error;
